import { GraduationCap, Briefcase, Shield } from "lucide-react";

const timeline = [
  {
    period: "Jun 2026 — Present",
    title: "Frontend Developer Intern | KaalCyberSec",
    org: "Contributing to frontend development pipelines to build modern, highly responsive, and intuitive user interfaces. Collaborating closely with remote cross-functional teams to optimize web platform performance and user experience.",
    icon: Briefcase,
    accent: true,
  },
  {
    period: "Dec 2022 — Jan 2023",
    title: "Graphic Design Intern | Skydoor EdTech",
    org: "Created engaging visual assets and promotional content utilizing Canva and Adobe Photoshop to boost brand engagement. Managed design assets and maintained consistent visual styling across social media and digital marketing channels.",
    icon: Briefcase,
    accent: false,
  },
  {
    period: "2025 — 2027",
    title: "Master of Computer Applications (MCA)",
    org: "School of Computer Science & Information Technology (SCSIT), DAVV, Indore",
    icon: GraduationCap,
    accent: false,
  },
  {
    period: "2022 — 2025",
    title: "Bachelor of Science (B.Sc.) in Computer Science",
    org: "PMB Gujarati Science College, Indore (Affiliated with DAVV University) • Grade: 7.80 CGPA",
    icon: GraduationCap,
    accent: false,
  },
  {
    period: "2021 — 2025",
    title: "Senior Under Officer (SUO) — National Cadet Corps",
    org: "Led a platoon of 40+ cadets • NCC 'C' Certificate Holder • Army Attachment Camp (Assam Regiment)",
    icon: Shield,
    accent: true,
  },
];
const competencies = [
  "Operational Planning",
  "Crisis Management",
  "Team Synchronization",
  "Strategic Communication",
];

const Experience = () => {
  return (
    <section
      id="exp"
      className="py-24 md:py-32 border-t border-white/5"
      data-testid="experience-section"
    >
      <div className="max-w-[1280px] mx-auto px-6 md:px-10 grid lg:grid-cols-12 gap-10">
        {/* Left heading */}
        <div className="lg:col-span-4">
          <p className="reveal font-mono-acc text-[10px] tracking-[0.32em] uppercase text-white/35 mb-4">
            [ 05 / Journey ]
          </p>
          <h2 className="reveal reveal-delay-1 text-4xl md:text-5xl font-extrabold uppercase tracking-tight leading-tight">
            Experience
            <span className="block text-[#E63946]">&amp; Leadership.</span>
          </h2>
          <p className="reveal reveal-delay-2 mt-5 text-[14px] text-white/45 leading-relaxed max-w-xs">
            Academic foundations, hands-on frontend work, and four years of NCC training
            that sharpened discipline, planning, and team coordination.
          </p>
        </div>

        {/* Right timeline */}
        <div className="lg:col-span-8">
          <div className="flex flex-col gap-3">
            {timeline.map((item, idx) => {
              const Icon = item.icon;
              return (
                <div
                  key={item.title}
                  data-testid={`timeline-item-${idx}`}
                  className={`reveal corner-ticks-sm border border-white/10 bg-white/[0.015] px-7 py-7 grid sm:grid-cols-[170px_1fr] gap-5 items-start ${
                    item.accent ? "corner-ticks" : ""
                  }`}
                >
                  <div className="flex flex-col gap-3">
                    <div
                      className={`w-9 h-9 flex items-center justify-center border ${
                        item.accent
                          ? "border-[#E63946]/40 bg-[#E63946]/10 text-[#E63946]"
                          : "border-white/10 text-[#E63946]"
                      }`}
                    >
                      <Icon size={15} />
                    </div>
                    <span className="font-mono-acc text-[10px] tracking-[0.14em] uppercase text-white/30">
                      {item.period}
                    </span>
                  </div>

                  <div>
                    <div className="text-[18px] md:text-[19px] font-bold tracking-tight mb-1.5">
                      {item.title}
                    </div>
                    <div className="text-[13px] text-white/45 leading-relaxed">{item.org}</div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Experience;
